1	export interface QuoteItem {
2	  type: string;
3	  cursed?: boolean;
4	  enchantment?: number;
5	}
6	
7	export interface QuoteInput {
8	  items: QuoteItem[];
9	  customer: { yearsWithMHPCO: number };
10	  isFollowUp: boolean;
11	}
12	
13	const PROCESSING_FEE = 5;
14	const FIRST_INSURANCE_RATE = 0.1;
15	const BLOCK_OF_3_PREMIUM = 60;
16	const CURSED_SURCHARGE_RATE = 0.5;
17	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
18	
19	const BASE_PREMIUM: Record<string, number> = {
20	  sword: 100,
21	  amulet: 60,
22	  staff: 80,
23	  potion: 40,
24	  rune: 25,
25	  moonstone: 25,
26	};
27	
28	export function quote(input: QuoteInput): number {
29	  let policyBase = 0;
30	
31	  const itemTypeCounts: Record<string, number> = {};
32	  for (const item of input.items) {
33	    itemTypeCounts[item.type] = (itemTypeCounts[item.type] || 0) + 1;
34	  }
35	
36	  for (const [type, count] of Object.entries(itemTypeCounts)) {
37	    if (count === 3) {
38	      policyBase += BLOCK_OF_3_PREMIUM;
39	    } else {
40	      policyBase += count * BASE_PREMIUM[type];
41	    }
42	  }
43	
44	  let itemSurcharges = 0;
45	  for (const item of input.items) {
46	    const itemBase = BASE_PREMIUM[item.type];
47	    if (item.cursed) {
48	      itemSurcharges += itemBase * CURSED_SURCHARGE_RATE;
49	    }
50	    if (item.enchantment !== undefined && item.enchantment >= 5) {
51	      itemSurcharges += itemBase * HIGH_ENCHANTMENT_SURCHARGE_RATE;
52	    }
53	  }
54	
55	  const firstInsuranceSurcharge = policyBase * FIRST_INSURANCE_RATE;
56	  const policyPremium = policyBase + itemSurcharges + firstInsuranceSurcharge;
57	  return Math.ceil(policyPremium + PROCESSING_FEE);
58	}
59	
60	export function claim() {
61	  return undefined;
62	}
